import React, { useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import './styles/global.css';

// Import pages
import Home from './pages/Home';
import About from './pages/About';
import Services from './pages/Services';
import Products from './pages/Products';
import Projects from './pages/Projects';
import Testimonials from './pages/Testimonials';
import Team from './pages/Team';
import Careers from './pages/Careers';
import Contact from './pages/Contact';
import ErpComparison from './pages/ErpComparison';

// Import components
import ContactHub from './components/ContactHub';

// Import Font Awesome
import '@fortawesome/fontawesome-free/css/all.min.css';

// Scroll restoration and title update component
function ScrollToTop() {
  const { pathname } = useLocation();

  useEffect(() => {
    window.scrollTo(0, 0);

    const titles = {
      '/': 'CloudMosaic | Enterprise Cloud & HR Solutions',
      '/about': 'About Us - CloudMosaic | Innovation-Driven Tech Company',
      '/services': 'Our Services - CloudMosaic',
      '/products': 'Our Products - CloudMosaic',
      '/projects': 'Our Projects - CloudMosaic',
      '/testimonials': 'Client Testimonials - CloudMosaic',
      '/team': 'Our Team - CloudMosaic',
      '/careers': 'Careers - CloudMosaic',
      '/contact': 'Contact Us - CloudMosaic',
      '/erp-comparison': 'Force ERP vs Traditional ERPs | CloudMosaic'
    };

    document.title = titles[pathname] || 'CloudMosaic';
  }, [pathname]);

  return null;
}

function App() {
  return (
    <Router>
      <ScrollToTop />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/services" element={<Services />} />
        <Route path="/products" element={<Products />} />
        <Route path="/projects" element={<Projects />} />
        <Route path="/testimonials" element={<Testimonials />} />
        <Route path="/team" element={<Team />} />
        <Route path="/careers" element={<Careers />} />
        <Route path="/contact" element={<Contact />} />
        <Route path="/erp-comparison" element={<ErpComparison />} />
      </Routes>
      <ContactHub />
    </Router>
  );
}

export default App;